solution_code:
#include <iostream>
#include <string>

int main()
{
    std::string haystack{};
    std::string needle{};
    std::cin >> haystack >> needle;

    std::size_t pos{ haystack.find(needle) };

    if (pos == std::string::npos)
        std::cout << "Not found" << '\n';
    else
        std::cout << "Found at position " << pos << '\n';

    return 0;
}
